import React, { useState, useEffect } from 'react';
import { useAuth } from './hooks/useAuth';
import { useCart } from './hooks/useCart';
import { useProducts } from './hooks/useProducts';

// Pages
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import ProductsPage from './pages/ProductsPage';
import CartPage from './pages/CartPage';
import CheckoutPage from './pages/CheckoutPage';
import OrdersPage from './pages/OrdersPage';
import ProfilePage from './pages/ProfilePage';
import AdminDashboard from './pages/admin/AdminDashboard';

// FIX #1: Resolve the initial page from localStorage so refresh doesn't lose context.
// We compute this once, outside the component, to use as the useState initializer.
const getInitialPage = () => {
  try {
    return localStorage.getItem('currentPage') || 'home';
  } catch {
    return 'home';
  }
};

const App = () => {
  // FIX #1: Seed currentPage from localStorage immediately — no flash to 'home'
  const [currentPage, setCurrentPage] = useState(getInitialPage);
  const [searchQuery, setSearchQuery] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Custom hooks
  const auth = useAuth();
  const cartHook = useCart(auth.user);
  const productsHook = useProducts();

  // FIX #1: Persist currentPage to localStorage on every change, but only after
  // auth has finished initializing (avoid persisting 'home' during the loading phase).
  useEffect(() => {
    if (!auth.isInitializing) {
      localStorage.setItem('currentPage', currentPage);
    }
  }, [currentPage, auth.isInitializing]);

  // Reload data whenever the user object becomes available (login OR rehydration)
  useEffect(() => {
    if (auth.user) {
      loadUserData();
    }
  }, [auth.user]);

  // FIX #1: After rehydration completes, enforce role-safe page routing.
  // If the stored page doesn't match the user's role, redirect to the correct default.
  useEffect(() => {
    if (auth.isInitializing) return;

    if (!auth.user) {
      // Unauthenticated: only allow public pages
      const publicPages = ['home', 'login', 'register'];
      if (!publicPages.includes(currentPage)) {
        setCurrentPage('home');
      }
      return;
    }

    if (auth.user.role === 'Admin') {
      const adminPages = ['admin', 'products'];
      if (!adminPages.includes(currentPage)) {
        setCurrentPage('admin');
      }
    } else {
      // Customer — guard against landing on admin page
      if (currentPage === 'admin') {
        setCurrentPage('products');
      }
    }
  }, [auth.isInitializing, auth.user]);

  const loadUserData = async () => {
    if (!auth.user) return;

    try {
      console.log('📂 Loading user data...');

      await Promise.all([
        productsHook.loadProducts().catch(err => {
          console.warn('⚠️ Failed to load products:', err);
          return [];
        }),
        cartHook.loadCart().catch(err => {
          console.warn('⚠️ Failed to load cart:', err);
          return [];
        }),
        auth.loadProfile().catch(err => {
          console.warn('⚠️ Failed to load profile:', err);
        }),
        auth.loadOrders().catch(err => {
          console.warn('⚠️ Failed to load orders:', err);
          return [];
        })
      ]);

      console.log('✅ User data loaded');
    } catch (err) {
      console.error('❌ Error loading user data:', err);
    }
  };

  // Common props passed to every page
  const pageProps = {
    currentPage,
    setCurrentPage,
    searchQuery,
    setSearchQuery,
    error,
    setError,
    loading,
    setLoading,
    user: auth.user,
    setUser: auth.setUser,
    cart: cartHook.cart,
    setCart: cartHook.setCart,
    products: productsHook.products,
    setProducts: productsHook.setProducts,
    orders: auth.orders,
    setOrders: auth.setOrders,
    handleLogout: auth.handleLogout,
    addToCart: cartHook.addToCart,
    updateCartQuantity: cartHook.updateCartQuantity,
    removeFromCart: cartHook.removeFromCart,
    clearCart: cartHook.clearCart,
    profileData: auth.profileData,
    setProfileData: auth.setProfileData,
    loadProducts: productsHook.loadProducts,
    loadOrders: auth.loadOrders,
    loadProfile: auth.loadProfile
  };

  // FIX #1: Block ALL rendering until the session rehydration check is complete.
  // Without this guard the routing logic below would see `user: null` and immediately
  // redirect to the Login page before the stored token has been read.
  if (auth.isInitializing) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-teal-500 border-t-transparent rounded-full animate-spin" />
          <p className="text-slate-600 font-semibold text-lg">Loading ShopAI...</p>
        </div>
      </div>
    );
  }

  // ── Unauthenticated routes ──────────────────────────────────────────────────
  if (!auth.user) {
    if (currentPage === 'login') {
      return <LoginPage {...pageProps} />;
    }
    if (currentPage === 'register') {
      return <RegisterPage {...pageProps} />;
    }
    return <HomePage {...pageProps} />;
  }

  // ── Authenticated routes ────────────────────────────────────────────────────
  if (auth.user.role === 'Admin' && currentPage === 'admin') {
    return <AdminDashboard {...pageProps} />;
  }

  switch (currentPage) {
    case 'products':
      return <ProductsPage {...pageProps} />;
    case 'cart':
      return <CartPage {...pageProps} />;
    case 'checkout':
      return <CheckoutPage {...pageProps} />;
    case 'orders':
      return <OrdersPage {...pageProps} />;
    case 'profile':
      return <ProfilePage {...pageProps} />;
    default:
      return <ProductsPage {...pageProps} />;
  }
};

export default App;
